import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { CertificateDto, CertificateTemplateDto, IssueCertificateDto, UploadTemplateDto } from '../models/certificate.models';

@Injectable({ providedIn: 'root' })
export class CertificateService {
  constructor(private api: ApiService) {}

  getMycertificates(): Observable<CertificateDto[]> {
    return this.api.get<CertificateDto[]>('certificates/my');
  }

  getUserCertificates(userId: number): Observable<CertificateDto[]> {
    return this.api.get<CertificateDto[]>(`certificates/user/${userId}`);
  }

  verify(code: string): Observable<CertificateDto | null> {
    return this.api.get<CertificateDto | null>(`certificates/verify/${code}`);
  }

  issue(dto: IssueCertificateDto): Observable<CertificateDto> {
    return this.api.post<CertificateDto>('certificates', dto);
  }

  getTemplates(): Observable<CertificateTemplateDto[]> {
    return this.api.get<CertificateTemplateDto[]>('certificates/templates');
  }

  uploadTemplate(dto: UploadTemplateDto): Observable<CertificateTemplateDto> {
    return this.api.post<CertificateTemplateDto>('certificates/templates', dto);
  }

  deleteTemplate(id: number): Observable<void> {
    return this.api.delete(`certificates/templates/${id}`);
  }
}
